import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "/etc/passwd";
        String directory = "/path/to/some/directory/";

        try {
            File file = new File(directory + userInput).getCanonicalFile();

            if (file.toPath().startsWith(new File(directory).toPath())) {
                FileInputStream fis = new FileInputStream(file);

                // Read contents of the file
                int content;
                while ((content = fis.read()) != -1) {
                    System.out.print((char) content);
                }

                fis.close();
            } else {
                System.out.println("Access to file outside directory is not allowed.");
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

